-- ============================================================
-- Quiz Seed: 2 Samuel Chapters 11–20
-- Target table: chapter_quizzes
-- Difficulties: kids (3 Qs), teens (5 Qs), adults (8 Qs) = 16 per chapter
-- Total: 10 chapters × 16 = 160 questions
-- correct_answer is always 'a'
-- ============================================================

-- ═══ 2 Samuel Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 11, 'kids', 1, 'What did King David do while his army was at war?', 'He stayed in Jerusalem and walked on his roof', 'He led the army in battle', 'He went to the temple to pray', 'He visited his friends', 'a', 'It came to pass that David tarried still at Jerusalem (2 Samuel 11:1), and he arose from his bed and walked upon the roof of the king''s house (11:2).'),
('2 Samuel', 11, 'kids', 2, 'What was the name of the woman David saw from his roof?', 'Bathsheba', 'Tamar', 'Abigail', 'Michal', 'a', 'David saw a woman washing herself and inquired about her, and one said, "Is not this Bathsheba?" (2 Samuel 11:3).'),
('2 Samuel', 11, 'kids', 3, 'What happened to Uriah during the battle after David sent a letter to Joab?', 'He was made a commander', 'He was sent home safely', 'He was killed in battle', 'He ran away', 'a', 'Joab placed Uriah in the hottest part of the battle, and the men of the city smote Uriah, and he died (2 Samuel 11:17).'),
-- Teens
('2 Samuel', 11, 'teens', 1, 'What time of year did David stay in Jerusalem while kings normally went to battle?', 'At the time when kings go forth to battle in spring', 'During the winter harvest', 'At the feast of tabernacles', 'During the feast of unleavened bread', 'a', 'It came to pass, after the year was expired, at the time when kings go forth to battle, that David sent Joab (2 Samuel 11:1).'),
('2 Samuel', 11, 'teens', 2, 'Who was Bathsheba''s husband?', 'Uriah the Hittite', 'Joab the commander', 'Abner the son of Ner', 'Benaiah the son of Jehoiada', 'a', 'David inquired about the woman and was told, "Is not this Bathsheba, the wife of Uriah the Hittite?" (2 Samuel 11:3).'),
('2 Samuel', 11, 'teens', 3, 'Why did Uriah refuse to go home to his wife when David urged him?', 'He said the ark and Israel and Judah abide in tents, so he could not eat, drink, and lie with his wife', 'He was angry at David for summoning him', 'He was ill and could not travel', 'He had taken a vow of fasting', 'a', 'Uriah said, "The ark, and Israel, and Judah, abide in tents...shall I then go into mine house?" (2 Samuel 11:11).'),
('2 Samuel', 11, 'teens', 4, 'What did David write in the letter he sent by Uriah''s own hand to Joab?', 'Set ye Uriah in the forefront of the hottest battle, and retire from him, that he may be smitten', 'Promote Uriah to be captain over the host', 'Give Uriah leave to return home to his family', 'Send Uriah back to Jerusalem immediately', 'a', 'David wrote in the letter, "Set ye Uriah in the forefront of the hottest battle, and retire ye from him, that he may be smitten, and die" (2 Samuel 11:15).'),
('2 Samuel', 11, 'teens', 5, 'What did David do after Bathsheba mourned for Uriah?', 'He brought her to his house and she became his wife', 'He sent her back to her father''s house', 'He appointed a guardian for her', 'He had her taken to the temple', 'a', 'When the mourning was past, David sent and fetched her to his house, and she became his wife (2 Samuel 11:27).'),
-- Adults
('2 Samuel', 11, 'adults', 1, 'Against what city was Joab fighting when Uriah was killed?', 'Rabbah of the children of Ammon', 'Jerusalem', 'Hebron', 'Gaza', 'a', 'Joab besieged Rabbah; David sent Joab and all Israel to Rabbah (2 Samuel 11:1), and Uriah died at the siege of Rabbah (11:17).'),
('2 Samuel', 11, 'adults', 2, 'What was Bathsheba''s message to David after their encounter?', '"I am with child"', '"My husband has returned from war"', '"Uriah knows what you have done"', '"Send me back to my father''s house"', 'a', 'Bathsheba conceived, and sent and told David, and said, "I am with child" (2 Samuel 11:5).'),
('2 Samuel', 11, 'adults', 3, 'What did David send to Uriah on the second night to try to get him to go home?', 'He made him drunk with wine', 'He gave him a gift of gold', 'He sent him a royal decree', 'He threatened him with punishment', 'a', 'David made Uriah drunk, but Uriah went not down to his house; he lay at the door of the king''s house (2 Samuel 11:13).'),
('2 Samuel', 11, 'adults', 4, 'What was Joab''s tactical cover story to explain Uriah''s death in the battle report to David?', 'He said the enemy shot arrows from the wall and some of David''s servants died', 'He said Uriah deserted his post', 'He said a plague broke out in the camp', 'He said Uriah fell in a skirmish outside the city gates', 'a', 'Joab instructed the messenger to say, "The men prevailed against us...thy servant Uriah the Hittite is dead also" (2 Samuel 11:23-24).'),
('2 Samuel', 11, 'adults', 5, 'How did David respond when the messenger reported Uriah''s death?', 'He said the sword devoureth one as well as another and told Joab to make his battle stronger', 'He wept and tore his garments', 'He gave Joab a great reward', 'He was silent and sent the messenger away', 'a', 'David told the messenger, "The sword devoureth one as well as another: make thy battle more strong against the city" (2 Samuel 11:25).'),
('2 Samuel', 11, 'adults', 6, 'What is the verdict the narrator gives at the very end of chapter 11?', 'The thing that David had done displeased the LORD', 'The LORD had mercy on David because of his repentance', 'Joab bore the greater guilt before God', 'David''s sin was covered by his kingship', 'a', 'But the thing that David had done displeased the LORD (2 Samuel 11:27).'),
('2 Samuel', 11, 'adults', 7, 'What was the full name of the woman David saw, according to the inquiry David made?', 'Bathsheba, the daughter of Eliam, the wife of Uriah the Hittite', 'Bathsheba, the daughter of Ahithophel', 'Bathsheba, the granddaughter of Ahithophel of Giloh', 'Bathsheba, the daughter of Shimei the Benjamite', 'a', 'One said, "Is not this Bathsheba, the daughter of Eliam, the wife of Uriah the Hittite?" (2 Samuel 11:3).'),
('2 Samuel', 11, 'adults', 8, 'What does Uriah''s loyalty in 2 Samuel 11 contrast against?', 'David''s adultery and murderous scheme while Uriah remained faithful to the covenant of war', 'Joab''s disloyalty to Uriah as a fellow soldier', 'The cowardice of the other soldiers who fled the battle', 'Nathan''s silence in the face of injustice', 'a', 'While David connived to cover his sin by having Uriah killed, Uriah refused even to go to his own home, saying the ark and Israel abide in tents (2 Samuel 11:11), highlighting David''s moral failure by contrast.');

-- ═══ 2 Samuel Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 12, 'kids', 1, 'Who did God send to speak to David about his sin?', 'Nathan the prophet', 'Elijah the prophet', 'Samuel the prophet', 'Gad the seer', 'a', 'The LORD sent Nathan unto David (2 Samuel 12:1).'),
('2 Samuel', 12, 'kids', 2, 'In Nathan''s story, what did the rich man take from the poor man?', 'His little ewe lamb', 'His house', 'His field', 'His donkey', 'a', 'The rich man took the poor man''s little ewe lamb that he had bought and nourished (2 Samuel 12:4).'),
('2 Samuel', 12, 'kids', 3, 'What was the name of the son born to David and Bathsheba who became very wise?', 'Solomon', 'Absalom', 'Amnon', 'Joab', 'a', 'Bathsheba bare a son, and he called his name Solomon: and the LORD loved him (2 Samuel 12:24).'),
-- Teens
('2 Samuel', 12, 'teens', 1, 'What were Nathan''s famous words to David after telling the parable of the ewe lamb?', '"Thou art the man"', '"God is watching you"', '"Repent or be destroyed"', '"The poor man cries to heaven"', 'a', 'Nathan said to David, "Thou art the man" (2 Samuel 12:7).'),
('2 Samuel', 12, 'teens', 2, 'What consequences did God announce to David through Nathan?', 'The sword shall never depart from his house, and evil would rise against him from his own house', 'David would be killed immediately', 'His kingdom would be given to his enemy Saul''s line', 'His army would be defeated in battle', 'a', 'God said, "The sword shall never depart from thine house...I will raise up evil against thee out of thine own house" (2 Samuel 12:10-11).'),
('2 Samuel', 12, 'teens', 3, 'What happened to the child born of David and Bathsheba''s sin?', 'He became sick and died on the seventh day', 'He grew up to become a judge', 'He was taken away and raised by Nathan', 'He was given to the priests', 'a', 'The LORD struck the child that Uriah''s wife bare unto David, and it was very sick...and on the seventh day the child died (2 Samuel 12:15, 18).'),
('2 Samuel', 12, 'teens', 4, 'What did David do when the child was sick that surprised his servants?', 'He lay upon the earth and fasted and wept all night', 'He offered sacrifices at the altar continually', 'He sent the child to the best healers in the land', 'He put on sackcloth and sat in the city gate', 'a', 'David lay all night upon the earth, and the elders of his house could not persuade him to eat bread (2 Samuel 12:16-17).'),
('2 Samuel', 12, 'teens', 5, 'What city did Joab send word to David to come and take credit for capturing?', 'Rabbah', 'Jericho', 'Gaza', 'Ashkelon', 'a', 'Joab sent messengers to David saying, "I have fought against Rabbah, and have taken the city of waters...come, and take the rest of the city" (2 Samuel 12:27-28).'),
-- Adults
('2 Samuel', 12, 'adults', 1, 'What did God say He had given David, listed by Nathan in the indictment?', 'The house of Israel and Judah, Saul''s house, Saul''s wives, and would have given even more', 'Only the kingdom of Judah', 'The tabernacle and the ark of the covenant', 'Victory in all his battles', 'a', 'God said through Nathan, "I gave thee thy master''s house...and gave thee the house of Israel and of Judah; and if that had been too little, I would moreover have given unto thee such and such things" (2 Samuel 12:8).'),
('2 Samuel', 12, 'adults', 2, 'What specific public consequence did God pronounce because David had done his deed in secret?', 'His wives would be taken before all Israel by his neighbor in broad daylight', 'His armies would be defeated publicly', 'His name would be cursed in the streets', 'His sons would be disinherited publicly', 'a', 'God said, "I will take thy wives before thine eyes, and give them unto thy neighbour...for thou didst it secretly: but I will do this thing before all Israel, and before the sun" (2 Samuel 12:11-12).'),
('2 Samuel', 12, 'adults', 3, 'What did David say immediately when Nathan declared, "Thou art the man"?', '"I have sinned against the LORD"', '"Have mercy on me, O God"', '"Let Nathan be my witness"', '"What can I do to make it right?"', 'a', 'David said unto Nathan, "I have sinned against the LORD" (2 Samuel 12:13).'),
('2 Samuel', 12, 'adults', 4, 'What was Nathan''s immediate response to David''s confession?', '"The LORD also hath put away thy sin; thou shalt not die"', '"Thou must offer a sacrifice for thy sin"', '"The people must know what thou hast done"', '"Thou must fast forty days"', 'a', 'Nathan said unto David, "The LORD also hath put away thy sin; thou shalt not die" (2 Samuel 12:13).'),
('2 Samuel', 12, 'adults', 5, 'How did David''s behavior change after the child actually died, surprising his servants?', 'He arose from the earth, washed, anointed himself, changed his apparel, worshipped, and then ate', 'He increased his mourning and refused food for another seven days', 'He went immediately to battle to distract his grief', 'He called Nathan back to interpret God''s will', 'a', 'When the child was dead, David arose from the earth, washed, anointed himself, changed his apparel, went into the house of the LORD and worshipped, then ate bread (2 Samuel 12:20).'),
('2 Samuel', 12, 'adults', 6, 'What reason did David give for ceasing to mourn after the child died?', '"Can I bring him back again? I shall go to him, but he shall not return to me"', '"God has taken him as a sign of forgiveness"', '"The child is now with Samuel in paradise"', '"Further mourning displeases the LORD"', 'a', 'David said, "Can I bring him back again? I shall go to him, but he shall not return to me" (2 Samuel 12:23).'),
('2 Samuel', 12, 'adults', 7, 'What other name did God, through Nathan, give to Solomon at birth?', 'Jedidiah, meaning beloved of the LORD', 'Emmanuel, meaning God with us', 'Josiah, meaning healed by God', 'Elijah, meaning my God is Yahweh', 'a', 'The LORD loved Solomon and sent Nathan the prophet, who called his name Jedidiah, because of the LORD (2 Samuel 12:24-25).'),
('2 Samuel', 12, 'adults', 8, 'What crown did David take from the king of Rabbah, and what was its weight?', 'The crown of Milcom weighing a talent of gold, with precious stones set on David''s head', 'A silver crown weighing fifty shekels', 'An iron crown weighing a hundred talents', 'A golden crown weighing two talents', 'a', 'David took their king''s crown...the weight whereof was a talent of gold with the precious stones: and it was set on David''s head (2 Samuel 12:30).');

-- ═══ 2 Samuel Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 13, 'kids', 1, 'Who was Tamar''s brother who harmed her?', 'Amnon', 'Absalom', 'Solomon', 'Adonijah', 'a', 'Amnon the son of David loved Tamar, the sister of Absalom the son of David (2 Samuel 13:1).'),
('2 Samuel', 13, 'kids', 2, 'What did Absalom do to Amnon because of what Amnon did to Tamar?', 'He killed Amnon', 'He sent him away from the palace', 'He told King David', 'He forgave him', 'a', 'Absalom commanded his servants to smite Amnon, and all the king''s sons arose and fled (2 Samuel 13:28-29).'),
('2 Samuel', 13, 'kids', 3, 'Where did Absalom flee after killing Amnon?', 'To Geshur', 'To Egypt', 'To Hebron', 'To Jericho', 'a', 'Absalom fled, and went to Geshur, and was there three years (2 Samuel 13:37-38).'),
-- Teens
('2 Samuel', 13, 'teens', 1, 'Who was Jonadab, and what did he advise Amnon to do?', 'He was Amnon''s cousin, a very subtle man, who advised Amnon to feign illness so Tamar would come to him', 'He was Amnon''s armor-bearer who advised him to flee the country', 'He was a palace official who warned Amnon to confess to David', 'He was a priest who counseled Amnon to offer a sacrifice', 'a', 'Jonadab was the son of Shimeah, David''s brother, a very subtil man, who advised Amnon to feign sickness and ask David to send Tamar to make him food (2 Samuel 13:3-5).'),
('2 Samuel', 13, 'teens', 2, 'What did Tamar say to Amnon before he assaulted her, pleading with him?', 'She said, "No such thing ought to be done in Israel: speak to the king; for he will not withhold me from thee"', 'She said, "I will tell our father David what you are planning"', 'She said, "God will punish you for this wickedness"', 'She said, "Let me go and I will keep silent about this"', 'a', 'Tamar said, "Nay, my brother, do not force me...speak unto the king; for he will not withhold me from thee" (2 Samuel 13:12-13).'),
('2 Samuel', 13, 'teens', 3, 'How did Amnon feel toward Tamar after he had committed his sin against her?', 'He hated her exceedingly, and the hatred was greater than the love with which he had loved her', 'He was filled with remorse and begged her forgiveness', 'He wanted to make her his wife', 'He ignored her completely', 'a', 'Then Amnon hated her exceedingly; so that the hatred wherewith he hated her was greater than the love wherewith he had loved her (2 Samuel 13:15).'),
('2 Samuel', 13, 'teens', 4, 'What was Absalom''s attitude toward Amnon in the days following the assault on Tamar?', 'Absalom spake unto his brother Amnon neither good nor bad, for Absalom hated Amnon', 'Absalom immediately confronted Amnon and demanded justice', 'Absalom pretended to forgive Amnon publicly', 'Absalom avoided Jerusalem so as not to see Amnon', 'a', 'Absalom spake unto his brother Amnon neither good nor bad: for Absalom hated Amnon, because he had forced his sister Tamar (2 Samuel 13:22).'),
('2 Samuel', 13, 'teens', 5, 'How long did Absalom dwell in Geshur before David''s soul longed to go to Absalom?', 'Three years', 'Seven years', 'One year', 'Five years', 'a', 'So Absalom fled, and went to Geshur, and was there three years (2 Samuel 13:38).'),
-- Adults
('2 Samuel', 13, 'adults', 1, 'What was the plan Absalom used to gather all the king''s sons so Amnon would be among them?', 'He invited all the king''s sons to a sheepshearing feast and asked the king to send Amnon specifically', 'He arranged a royal banquet at the palace', 'He organized a hunting expedition in the hills of Ephraim', 'He held a sacrifice and invited the royal family', 'a', 'Absalom had sheepshearers in Baal-hazor, and invited all the king''s sons; then he asked the king, "Let Amnon go with us" (2 Samuel 13:23-27).'),
('2 Samuel', 13, 'adults', 2, 'What instruction did Absalom give his servants regarding the timing of killing Amnon?', '"When Amnon''s heart is merry with wine, then kill him"', '"Strike him when he is alone and away from the others"', '"Wait until he sleeps and then smite him"', '"Kill him only if he refuses to leave the feast"', 'a', 'Absalom commanded his servants, "Mark ye now when Amnon''s heart is merry with wine, and when I say unto you, Smite Amnon; then kill him, fear not" (2 Samuel 13:28).'),
('2 Samuel', 13, 'adults', 3, 'What false report initially reached David about the massacre at Absalom''s feast?', 'That Absalom had slain all the king''s sons', 'That Amnon alone had started a riot and been killed accidentally', 'That the Philistines had attacked the feast', 'That Joab had killed Amnon by royal command', 'a', 'A messenger told David, "Absalom hath slain all the king''s sons, and there is not one of them left" (2 Samuel 13:30).'),
('2 Samuel', 13, 'adults', 4, 'Who corrected the false report and what was the truth he told David?', 'Jonadab corrected it, saying only Amnon was dead, as Absalom had determined this since the day Amnon forced Tamar', 'Nathan the prophet corrected it, declaring it was God''s judgment', 'Joab corrected it, having received information from spies', 'The returning servants corrected it when they arrived', 'a', 'Jonadab said to David, "Let not my lord suppose that they have slain all the young men the king''s sons; for Amnon only is dead: for by the appointment of Absalom this hath been determined from the day that he forced his sister Tamar" (2 Samuel 13:32-33).'),
('2 Samuel', 13, 'adults', 5, 'Where had Tamar lived after the assault, and what was her condition?', 'She lived desolate in her brother Absalom''s house', 'She was taken into the king''s harem for protection', 'She returned to her mother''s household', 'She was sent to live in the tabernacle precincts', 'a', 'Tamar remained desolate in her brother Absalom''s house (2 Samuel 13:20).'),
('2 Samuel', 13, 'adults', 6, 'What was David''s reaction when he heard of Amnon''s assault on Tamar?', 'He was very wroth but did not grieve or punish Amnon because he loved him', 'He immediately punished Amnon and stripped him of his inheritance', 'He banished Amnon from Jerusalem for a year', 'He called for a public trial before the elders', 'a', 'When King David heard of all these things, he was very wroth (2 Samuel 13:21), yet he did not punish Amnon because he loved him as his firstborn.'),
('2 Samuel', 13, 'adults', 7, 'Who was Absalom''s grandfather in Geshur, where he fled?', 'Talmai, king of Geshur', 'Achish, king of Gath', 'Nahash, king of Ammon', 'Hadadezer, king of Zobah', 'a', 'Absalom fled, and went to Talmai, the son of Ammihud, king of Geshur (2 Samuel 13:37).'),
('2 Samuel', 13, 'adults', 8, 'What does chapter 13 reveal as the beginning of the fulfillment of Nathan''s prophecy in chapter 12?', 'It shows "the sword shall never depart from thine house" beginning through rape and fratricide within David''s own family', 'It shows God''s blessing transferred from David to Solomon immediately', 'It demonstrates that Joab''s influence corrupted the royal household', 'It reveals that Saul''s curse on David''s line came to pass', 'a', 'Nathan had warned that evil would arise from David''s own house (2 Samuel 12:11); the violation of Tamar and murder of Amnon show that prophecy beginning to be fulfilled (2 Samuel 13:14, 28-29).');

-- ═══ 2 Samuel Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 14, 'kids', 1, 'From what city did Joab bring a wise woman to help bring Absalom back?', 'Tekoa', 'Bethlehem', 'Hebron', 'Jericho', 'a', 'Joab sent to Tekoa, and fetched thence a wise woman (2 Samuel 14:2).'),
('2 Samuel', 14, 'kids', 2, 'How many years was Absalom known for having no blemish and being very handsome?', 'He was praised for his beauty in all Israel with no blemish from head to foot', 'He was praised only in Judah', 'Only his hair was mentioned as beautiful', 'He was not described as handsome', 'a', 'In all Israel there was none to be so much praised as Absalom for his beauty: from the sole of his foot even to the crown of his head there was no blemish in him (2 Samuel 14:25).'),
('2 Samuel', 14, 'kids', 3, 'How long was Absalom in Jerusalem before King David finally agreed to see him?', 'Two full years before Absalom sent for Joab, then David kissed him', 'One month', 'Seven years', 'Only a few days', 'a', 'Absalom dwelt two full years in Jerusalem, and saw not the king''s face (2 Samuel 14:28), then Joab arranged the reconciliation and David kissed Absalom (14:33).'),
-- Teens
('2 Samuel', 14, 'teens', 1, 'What was the fictional story the wise woman of Tekoa told David?', 'She said she was a widow whose two sons fought, one killing the other, and the family wanted to execute the surviving son', 'She said her husband had been killed in battle and she was left destitute', 'She said her son had been falsely accused and condemned to death', 'She said two brothers fought over an inheritance and one was exiled', 'a', 'The woman pretended to be a widow who had two sons; one smote the other and slew him, and the whole family sought to kill the survivor (2 Samuel 14:5-7).'),
('2 Samuel', 14, 'teens', 2, 'What point did the woman of Tekoa make that applied to David and Absalom?', 'She said the king had not fetched home again his banished, and used the figure of water spilt on the ground that cannot be gathered up', 'She said that vengeance belongs only to the LORD', 'She argued that exile was worse than death', 'She compared Absalom to a lost sheep that needed finding', 'a', 'The woman said, "For we must needs die, and are as water spilt on the ground...neither doth God respect any person: yet doth he devise means, that his banished be not expelled from him" (2 Samuel 14:14).'),
('2 Samuel', 14, 'teens', 3, 'How did David discern that Joab was behind the wise woman''s visit?', 'David perceived that Joab had sent her, and she confessed that Joab had put all the words in her mouth', 'A servant overheard Joab giving her instructions', 'Joab himself came forward and admitted it', 'The woman''s story was too well-crafted for a simple widow', 'a', 'David said, "Is not the hand of Joab with thee in all this?" and the woman acknowledged that Joab had commanded her and put all those words in her mouth (2 Samuel 14:19).'),
('2 Samuel', 14, 'teens', 4, 'How did Absalom get Joab to come to him after Joab refused to visit him twice?', 'He set Joab''s barley field on fire', 'He sent a threatening letter to Joab', 'He appealed to the king through a servant', 'He blocked the road to the palace', 'a', 'Absalom said to his servants, "Set Joab''s field on fire." So his servants set the field on fire, and then Joab came to Absalom''s house (2 Samuel 14:30-31).'),
('2 Samuel', 14, 'teens', 5, 'What was the weight of Absalom''s hair when he cut it at the end of each year?', 'Two hundred shekels after the king''s weight', 'One hundred shekels', 'Fifty shekels', 'Three hundred shekels', 'a', 'When he polled his head...he weighed the hair of his head at two hundred shekels after the king''s weight (2 Samuel 14:26).'),
-- Adults
('2 Samuel', 14, 'adults', 1, 'Why did Joab devise the plan to bring Absalom back to Jerusalem?', 'Because Joab perceived that the king''s heart was toward Absalom', 'Because Absalom had bribed Joab with silver', 'Because the army was loyal to Absalom and demanded his return', 'Because Nathan the prophet instructed Joab', 'a', 'Joab the son of Zeruiah perceived that the king''s heart was toward Absalom (2 Samuel 14:1).'),
('2 Samuel', 14, 'adults', 2, 'What did the wise woman say to David comparing God''s nature to the king''s actions?', 'She said God devises means that his banished be not expelled from him, implying David should do the same', 'She said God always punishes the guilty without mercy', 'She said God rewards the king who shows justice above mercy', 'She said God told her in a vision to bring Absalom home', 'a', 'The woman said, "God doth not take away life; but devises means, that his banished be not expelled from him" (2 Samuel 14:14), applying God''s character as a model for David to recall Absalom.'),
('2 Samuel', 14, 'adults', 3, 'What exact terms did David grant when he recalled Absalom?', 'Let Absalom turn to his own house and let him not see the king''s face', 'Full reconciliation with Absalom restored as crown prince', 'Absalom could live in Jerusalem only outside the palace quarter', 'Absalom had to serve five years in the army before being forgiven', 'a', 'David said, "Let him turn to his own house, and let him not see my face." So Absalom returned to his own house, and saw not the king''s face (2 Samuel 14:24).'),
('2 Samuel', 14, 'adults', 4, 'How many sons and one daughter did Absalom have, and what was his daughter''s name?', 'Three sons and one daughter named Tamar', 'Two sons and one daughter named Abigail', 'Four sons and two daughters', 'One son and one daughter named Miriam', 'a', 'Unto Absalom there were born three sons, and one daughter, whose name was Tamar: she was a woman of a fair countenance (2 Samuel 14:27).'),
('2 Samuel', 14, 'adults', 5, 'What argument did Absalom use with Joab when he finally arranged a meeting?', 'He said it would have been better for him to have remained in Geshur, and asked Joab to arrange for him to see the king''s face or else kill him', 'He threatened to expose Joab''s role in the field burning', 'He offered Joab gold and silver to restore his standing', 'He said the people demanded his full restoration', 'a', 'Absalom said to Joab, "It had been good for me to have been there still: now therefore let me see the king''s face; and if there be any iniquity in me, let him kill me" (2 Samuel 14:32).'),
('2 Samuel', 14, 'adults', 6, 'How did David greet Absalom when they were finally reconciled?', 'The king kissed Absalom', 'The king embraced Absalom and wept', 'The king gave Absalom a seat at his table', 'The king restored Absalom''s rank publicly', 'a', 'Absalom came to the king, and bowed himself on his face to the ground before the king: and the king kissed Absalom (2 Samuel 14:33).'),
('2 Samuel', 14, 'adults', 7, 'What does Absalom''s burning of Joab''s field reveal about his character?', 'A ruthless willingness to use destructive means to force others to serve his agenda', 'Frustration that his legitimate requests were being ignored', 'A righteous demand for justice after years of unjust exile', 'A calculated act meant to demonstrate his power to the people', 'a', 'When Joab refused to come to him twice, Absalom told his servants to set Joab''s barley field ablaze to compel Joab''s attention (2 Samuel 14:30), revealing a pattern of coercion that foreshadows his later rebellion.'),
('2 Samuel', 14, 'adults', 8, 'What is the theological irony in Absalom''s partial restoration described in chapter 14?', 'David''s incomplete forgiveness — recalling Absalom but refusing to see him — sowed the bitterness that grew into full rebellion in chapter 15', 'God blessed David for his measured response to Absalom''s sin', 'Joab''s intervention was the beginning of his own downfall', 'Absalom''s beauty was a sign of divine favor restoring him fully', 'a', 'Though David allowed Absalom to return to Jerusalem, he refused to see him for two full years (2 Samuel 14:24, 28), a half-hearted reconciliation that left Absalom embittered and primed for the rebellion that follows in chapter 15.');

-- ═══ 2 Samuel Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 15, 'kids', 1, 'What did Absalom use to make himself look important each day?', 'Chariots and horses and fifty men to run before him', 'A golden crown and royal robes', 'A large army of soldiers beside him', 'Beautiful gifts for everyone he met', 'a', 'Absalom prepared him chariots and horses, and fifty men to run before him (2 Samuel 15:1).'),
('2 Samuel', 15, 'kids', 2, 'What city did Absalom go to when he began his rebellion and was made king?', 'Hebron', 'Jerusalem', 'Bethlehem', 'Jericho', 'a', 'Absalom arose, and went to Hebron (2 Samuel 15:9-10).'),
('2 Samuel', 15, 'kids', 3, 'What did David do when he heard that Absalom had taken over?', 'He fled from Jerusalem with all his household', 'He called his army together to fight', 'He prayed in the temple', 'He sent a messenger to Absalom', 'a', 'David said to all his servants, "Arise, and let us flee...lest he overtake us suddenly." So David and all his household fled on foot (2 Samuel 15:14-16).'),
-- Teens
('2 Samuel', 15, 'teens', 1, 'How did Absalom steal the hearts of the men of Israel?', 'He stood at the gate and intercepted men with disputes, saying the king had no deputy, and that he wished he were judge so he could do them justice', 'He held great feasts and gave gifts to the people', 'He gathered the army and promised them land', 'He spoke against David in the temple courts', 'a', 'Absalom would intercept men coming to the king for judgment and say, "There is no man deputed of the king to hear thee...O that I were made judge in the land...I would do him justice": so Absalom stole the hearts of the men of Israel (2 Samuel 15:2-6).'),
('2 Samuel', 15, 'teens', 2, 'What vow did Absalom claim he had made to get permission to go to Hebron?', 'He said he had vowed a vow to the LORD in Geshur that if the LORD brought him to Jerusalem, he would serve the LORD in Hebron', 'He said he had promised God a sacrifice if his rebellion succeeded', 'He said he had vowed to offer a firstfruits offering in Hebron', 'He said he had promised to visit his mother''s grave in Hebron', 'a', 'Absalom said to David, "I pray thee, let me go and pay my vow, which I have vowed unto the LORD, in Hebron" (2 Samuel 15:7-8).'),
('2 Samuel', 15, 'teens', 3, 'Who was Hushai the Archite and what mission did David give him?', 'He was David''s friend, sent back to Jerusalem to defeat Ahithophel''s counsel and spy for David', 'He was a military commander sent to defend Jerusalem', 'He was a priest sent to keep the ark in Jerusalem', 'He was a scribe sent to record the events of the rebellion', 'a', 'Hushai the Archite, David''s friend, came to David, and David sent him back saying, "Return to the city...defeat the counsel of Ahithophel" and report to David through the priests (2 Samuel 15:32-36).'),
('2 Samuel', 15, 'teens', 4, 'What did David ask the priests Zadok and Abiathar to do when they brought the ark out of Jerusalem?', 'He asked them to carry the ark back into the city and remain there as spies', 'He asked them to bring the ark with the army to fight Absalom', 'He asked them to hide the ark in a safe place outside the city', 'He asked them to offer sacrifices at the Mount of Olives', 'a', 'David told Zadok, "Carry back the ark of God into the city...thou art a seer: return into the city in peace, and your two sons with you, Ahimaaz and Jonathan" to serve as messengers (2 Samuel 15:25-29).'),
('2 Samuel', 15, 'teens', 5, 'How did David go up the Mount of Olives as he fled Jerusalem?', 'He went up barefoot and weeping, with his head covered, and all the people with him covered their heads and wept', 'He rode a horse and ordered silence', 'He walked alone ahead of all his servants', 'He was carried in a litter because of grief', 'a', 'David went up by the ascent of mount Olivet, and wept as he went up, and had his head covered, and he went barefoot: and all the people...every man with his head covered wept as they went up (2 Samuel 15:30).'),
-- Adults
('2 Samuel', 15, 'adults', 1, 'How long did Absalom''s campaign to steal the hearts of Israel last before he felt confident to rebel?', 'Forty years', 'Four years', 'Ten years', 'Seven years', 'a', 'After forty years Absalom said to the king, "I pray thee, let me go and pay my vow" — note some manuscripts read four years, but the Hebrew text says forty years (2 Samuel 15:7).'),
('2 Samuel', 15, 'adults', 2, 'What was the significance of Absalom choosing Hebron as the site of his coronation?', 'Hebron was David''s original capital where he had first been made king over Judah, giving Absalom''s coup symbolic legitimacy', 'Hebron was the site of the tabernacle and the ark of God', 'Hebron was Absalom''s birthplace', 'Hebron was near the Philistine border giving Absalom military advantage', 'a', 'David had reigned in Hebron seven years before Jerusalem (2 Samuel 2:11, 5:5); Absalom''s choosing Hebron as his coronation site (2 Samuel 15:10) exploited that symbolic capital.'),
('2 Samuel', 15, 'adults', 3, 'Who was Ahithophel and why was his involvement in Absalom''s rebellion particularly significant to David?', 'Ahithophel was David''s own counselor, and his defection was so grievous David prayed God would turn his counsel into foolishness', 'Ahithophel was the head of the Sanhedrin whose support gave the rebellion legal authority', 'Ahithophel was a Philistine diplomat whose alliance strengthened Absalom militarily', 'Ahithophel was Joab''s uncle who gave Absalom military expertise', 'a', 'David was told, "Ahithophel is among the conspirators with Absalom"; David said, "O LORD, I pray thee, turn the counsel of Ahithophel into foolishness" (2 Samuel 15:31).'),
('2 Samuel', 15, 'adults', 4, 'How many men did Absalom invite from Jerusalem under false pretenses to go to Hebron with him?', 'Two hundred men who went in their simplicity and knew not any thing', 'Five hundred loyal soldiers', 'Twelve tribal elders', 'A thousand men of valor', 'a', 'With Absalom went two hundred men out of Jerusalem...and they went in their simplicity, and knew not any thing (2 Samuel 15:11).'),
('2 Samuel', 15, 'adults', 5, 'What did Ittai the Gittite say when David urged him to turn back rather than flee with him?', 'He swore by the LORD that as David lived, whether in death or life, he would not leave David', 'He said he would fight for David until his last breath', 'He said God had spoken to him in a dream to stay with David', 'He said his soldiers needed David''s leadership to survive', 'a', 'Ittai answered, "As the LORD liveth, and as my lord the king liveth, surely in what place my lord the king shall be, whether in death or life, even there also will thy servant be" (2 Samuel 15:21).'),
('2 Samuel', 15, 'adults', 6, 'What was the intelligence network David set up before leaving Jerusalem?', 'Zadok and Abiathar with the ark inside Jerusalem, their sons as runners, and Hushai to counter Ahithophel''s counsel and report through the priests', 'Joab left behind with a hidden garrison in the city', 'Mephibosheth tasked with observing Absalom''s movements', 'A network of merchants traveling between the armies', 'a', 'David arranged for Zadok and Abiathar to stay in Jerusalem with the ark, their sons Ahimaaz and Jonathan as messengers, and Hushai to defeat Ahithophel''s counsel (2 Samuel 15:27-36).'),
('2 Samuel', 15, 'adults', 7, 'What does Psalm 3 tradition associate with David''s flight in this chapter?', 'Psalm 3 is titled "A Psalm of David, when he fled from Absalom his son," beginning "LORD, how are they increased that trouble me"', 'Psalm 23 was composed during the flight across the Jordan', 'Psalm 51 was written at the Mount of Olives as David wept', 'Psalm 46 was David''s prayer while crossing the Jordan River', 'a', 'The superscription of Psalm 3 reads, "A Psalm of David, when he fled from Absalom his son," connecting it to this flight over the Mount of Olives (2 Samuel 15:30).'),
('2 Samuel', 15, 'adults', 8, 'What does David''s statement about the ark in 2 Samuel 15:25-26 reveal about his theology of God''s sovereignty?', 'He says if the LORD has delight in him He will bring him again, but if not, "here I am, let him do to me as seemeth good unto him," showing submission to God''s will', 'He declares the ark must go with the army or Israel will lose the battle', 'He believes God''s presence guarantees his return to the throne', 'He uses the ark as a political symbol to maintain priestly loyalty', 'a', 'David said, "Carry back the ark of God into the city: if I shall find favour in the eyes of the LORD, he will bring me again...but if he thus say, I have no delight in thee; behold, here am I, let him do to me as seemeth good unto him" (2 Samuel 15:25-26).');

-- ═══ 2 Samuel Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 16, 'kids', 1, 'Who met David with donkeys loaded with food as he fled Jerusalem?', 'Ziba, the servant of Mephibosheth', 'Joab the army commander', 'Nathan the prophet', 'Abiathar the priest', 'a', 'Ziba the servant of Mephibosheth met David with a couple of asses saddled, with bread, summer fruits, and wine (2 Samuel 16:1).'),
('2 Samuel', 16, 'kids', 2, 'Who cursed David with stones and dirt as David and his men passed by?', 'Shimei, the son of Gera', 'Mephibosheth', 'Absalom', 'Sheba the Benjamite', 'a', 'Shimei the son of Gera...came forth, and cursed still as he came, and he threw stones at David (2 Samuel 16:5, 13).'),
('2 Samuel', 16, 'kids', 3, 'Who came to Jerusalem and met Absalom, pretending to be on Absalom''s side, when really he was David''s spy?', 'Hushai the Archite', 'Joab', 'Zadok the priest', 'Ittai the Gittite', 'a', 'Hushai the Archite, David''s friend, came unto Absalom: and Absalom said unto Hushai, "Is this thy kindness to thy friend?" (2 Samuel 16:16-17).'),
-- Teens
('2 Samuel', 16, 'teens', 1, 'What did Ziba claim about Mephibosheth when he brought David provisions?', 'He said Mephibosheth was staying in Jerusalem saying, "To day shall the house of Israel restore me the kingdom of my father"', 'He said Mephibosheth had fled to Geshur to be safe', 'He said Mephibosheth was too ill to travel', 'He said Mephibosheth had refused to help either side', 'a', 'Ziba answered, "Behold, he abideth at Jerusalem: for he said, To day shall the house of Israel restore me the kingdom of my father Saul" (2 Samuel 16:3).'),
('2 Samuel', 16, 'teens', 2, 'What did David give Ziba as a reward for his provision?', 'All that pertained to Mephibosheth', 'A hundred talents of silver', 'A village and its lands', 'The position of royal steward', 'a', 'The king said to Ziba, "Behold, thine are all that pertained unto Mephibosheth" (2 Samuel 16:4).'),
('2 Samuel', 16, 'teens', 3, 'From what tribe was Shimei, and why was he cursing David?', 'He was of the family of Saul''s house of the tribe of Benjamin, and he cursed David saying God had given the kingdom to Absalom because of David''s blood guiltiness', 'He was of the tribe of Reuben, cursing David for taxing the northern tribes', 'He was of the tribe of Dan, cursing David for moving the ark to Jerusalem', 'He was of the tribe of Gad, cursing David for failing to avenge Abner', 'a', 'Shimei the son of Gera, a Benjamite of the house of Saul, came forth and cursed, saying, "The LORD hath returned upon thee all the blood of the house of Saul...the LORD hath delivered the kingdom into the hand of Absalom" (2 Samuel 16:5, 8).'),
('2 Samuel', 16, 'teens', 4, 'What did David say when Abishai offered to go cut off Shimei''s head for cursing the king?', 'He said let him curse, for the LORD had bidden him to curse David, and perhaps the LORD would look on his affliction', 'He said, "Bring him to me so I may judge him myself"', 'He said, "Do what you must to protect the king''s honor"', 'He said, "Not today, but he shall answer for this later"', 'a', 'David said, "Let him curse, because the LORD hath said unto him, Curse David...Let him alone, and let him curse; for the LORD hath bidden him...It may be that the LORD will look on mine affliction" (2 Samuel 16:10-12).'),
('2 Samuel', 16, 'teens', 5, 'What did Absalom do in Jerusalem on the advice of Ahithophel that fulfilled Nathan''s prophecy?', 'He went in unto his father''s concubines in a tent on the roof before all Israel', 'He sat on David''s throne and made sacrifices at the altar', 'He took possession of the royal treasury', 'He held a public coronation ceremony in the palace courtyard', 'a', 'Ahithophel counseled Absalom to go in unto his father''s concubines; they spread Absalom a tent upon the top of the house, and Absalom went in unto his father''s concubines in the sight of all Israel (2 Samuel 16:21-22), fulfilling 2 Samuel 12:11-12.'),
-- Adults
('2 Samuel', 16, 'adults', 1, 'What is the specific purpose Ahithophel gave Absalom for taking his father''s concubines?', 'So that all Israel shall hear that thou art abhorred of thy father: then shall the hands of all that are with thee be strong', 'To demonstrate that Absalom had fully claimed the throne', 'To punish the concubines for their loyalty to David', 'To fulfill a political custom of the ancient Near East', 'a', 'Ahithophel said, "Go in unto thy father''s concubines...and all Israel shall hear that thou art abhorred of thy father: then shall the hands of all that are with thee be strong" (2 Samuel 16:21).'),
('2 Samuel', 16, 'adults', 2, 'How is Ahithophel''s counsel described in verse 23 of chapter 16?', 'The counsel of Ahithophel was as if a man had enquired at the oracle of God', 'Ahithophel''s counsel was sharper than a two-edged sword', 'Ahithophel was the wisest man in all the eastern kingdoms', 'His words were as fire and carried the authority of a prophet', 'a', 'The counsel of Ahithophel, which he counselled in those days, was as if a man had enquired at the oracle of God: so was all the counsel of Ahithophel both with David and with Absalom (2 Samuel 16:23).'),
('2 Samuel', 16, 'adults', 3, 'What greeting did Hushai give Absalom when he arrived in Jerusalem, and how did Hushai justify it?', 'He cried "God save the king!" and when questioned he said he would serve whoever the LORD and the people chose', 'He bowed down before Absalom and offered him military counsel', 'He said he had come to tell Absalom of weaknesses in David''s defenses', 'He presented a gift of silver to demonstrate his loyalty to Absalom', 'a', 'Hushai said to Absalom, "God save the king," and when Absalom questioned his loyalty to his friend David, Hushai said, "Nay; but whom the LORD, and this people, and all the men of Israel, choose, his will I be" (2 Samuel 16:16-18).'),
('2 Samuel', 16, 'adults', 4, 'What does Ziba''s self-interested report about Mephibosheth in chapter 16 set up for chapter 19?', 'It sets up the reversal where Mephibosheth gives his own account to David and David has to divide the land between them', 'It establishes Ziba as the new steward over all of Saul''s estate permanently', 'It shows David''s generosity in rewarding loyalty during his flight', 'It demonstrates that loyalty to the Saulide line had permanently ended', 'a', 'Ziba''s false accusation that Mephibosheth expected to reclaim Saul''s kingdom (2 Samuel 16:3) is later contradicted by Mephibosheth himself (2 Samuel 19:24-28), exposing Ziba as a liar; David splits the estate between them (19:29).'),
('2 Samuel', 16, 'adults', 5, 'What theological principle did David articulate in his response to Shimei''s cursing?', 'That even the cursing of an enemy may be permitted by God as chastisement, and should be endured with humility rather than violent retaliation', 'That kings are immune from curses and Shimei''s words had no power', 'That to retaliate against curses compounds the original sin', 'That revenge belongs to the king and should be delayed until victory', 'a', 'David said, "Let him curse, because the LORD hath said unto him, Curse David...the LORD hath bidden him...It may be that the LORD will look on mine affliction, and that the LORD will requite me good for his cursing this day" (2 Samuel 16:10-12).'),
('2 Samuel', 16, 'adults', 6, 'Why did Absalom question Hushai''s loyalty when he arrived in Jerusalem?', 'He asked why Hushai had not gone with his friend David when David fled', 'He suspected Hushai of being a spy based on a report from Ahithophel', 'He knew Hushai had served David as a counselor for many years', 'He received a report that Hushai had been seen consulting with the priests', 'a', 'Absalom said to Hushai, "Is this thy kindness to thy friend? why wentest thou not with thy friend?" (2 Samuel 16:17).'),
('2 Samuel', 16, 'adults', 7, 'What supplies did Ziba bring to David and his men?', 'Two hundred loaves of bread, an hundred bunches of raisins, an hundred of summer fruits, and a bottle of wine', 'A cart of grain and two oxen for sacrifice', 'Gold and silver for David''s military expenses', 'Weapons and armor for David''s soldiers', 'a', 'Ziba had two hundred loaves of bread, and an hundred bunches of raisins, and an hundred of summer fruits, and a bottle of wine (2 Samuel 16:1).'),
('2 Samuel', 16, 'adults', 8, 'What does the detail that Absalom''s tent was pitched on the very roof of the house indicate about the fulfillment of Nathan''s prophecy?', 'It mirrors the exact setting of David''s own sin — David had seen Bathsheba from his rooftop — and now Absalom''s sin on the same rooftop was done publicly, fulfilling "before the sun"', 'It shows Absalom wanted to demonstrate his military control of the palace heights', 'It fulfilled the ancient custom of a new king claiming the highest point of the palace', 'It indicated that Absalom feared an assassination attempt inside the palace', 'a', 'God had said through Nathan, "I will take thy wives...and he shall lie with thy wives in the sight of this sun" (2 Samuel 12:11-12); David had stood on his roof to see Bathsheba (11:2), and now Absalom committed his sin on that very rooftop "in the sight of all Israel, and before the sun" (16:22).');

-- ═══ 2 Samuel Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 17, 'kids', 1, 'Whose advice did Absalom follow — Ahithophel''s or Hushai''s?', 'Hushai''s advice', 'Ahithophel''s advice', 'Joab''s advice', 'The elders'' advice', 'a', 'Absalom and all the men of Israel said, "The counsel of Hushai the Archite is better than the counsel of Ahithophel" (2 Samuel 17:14).'),
('2 Samuel', 17, 'kids', 2, 'What did Ahithophel do when he saw his advice was not followed?', 'He saddled his donkey, went home, set his house in order, and hanged himself', 'He fled to Egypt', 'He joined David''s army', 'He threw himself on the mercy of the king', 'a', 'When Ahithophel saw that his counsel was not followed, he saddled his ass, arose, gat him home to his house...and hanged himself (2 Samuel 17:23).'),
('2 Samuel', 17, 'kids', 3, 'Where did David cross to escape Absalom''s army?', 'He crossed over Jordan', 'He hid in a cave in the wilderness', 'He went to the Philistine city of Gath', 'He sailed across the Sea of Galilee', 'a', 'David arose, and all the people that were with him, and they passed over Jordan (2 Samuel 17:22).'),
-- Teens
('2 Samuel', 17, 'teens', 1, 'What was Ahithophel''s specific counsel to Absalom?', 'Let me choose twelve thousand men and arise and pursue David this night and smite him alone while he is weary and weak-handed', 'Build a strong defense of Jerusalem and wait for David to surrender', 'Make alliances with the Philistines and surround David from all sides', 'Call all Israel together before attacking to ensure maximum force', 'a', 'Ahithophel counseled, "Let me now choose out twelve thousand men, and I will arise and pursue after David this night: And I will come upon him while he is weary and weak handed...I will smite the king only" (2 Samuel 17:1-2).'),
('2 Samuel', 17, 'teens', 2, 'What was Hushai''s counter-counsel that convinced Absalom?', 'He said David and his men are mighty men and Ahithophel''s plan would fail; gather all Israel from Dan to Beersheba and lead them personally', 'He said Ahithophel''s plan was good but the timing was wrong', 'He counseled Absalom to send diplomats to David first', 'He suggested surrounding the Jordan crossings to trap David', 'a', 'Hushai said Ahithophel''s counsel was not good, for David''s men were mighty; instead "I counsel that all Israel be generally gathered unto thee...and thou go to battle in thine own person" (2 Samuel 17:7-11).'),
('2 Samuel', 17, 'teens', 3, 'Why did the LORD arrange for Absalom to follow Hushai''s counsel instead of Ahithophel''s?', 'Because the LORD had appointed to defeat the good counsel of Ahithophel to bring evil upon Absalom', 'Because Hushai was more persuasive than Ahithophel', 'Because the elders of Israel voted for Hushai''s plan', 'Because Absalom''s generals preferred Hushai''s larger strategy', 'a', 'The LORD had appointed to defeat the good counsel of Ahithophel, to the intent that the LORD might bring evil upon Absalom (2 Samuel 17:14).'),
('2 Samuel', 17, 'teens', 4, 'How did the message from Hushai reach David — who were the messengers?', 'A wench told Ahimaaz and Jonathan who hid in a well at Bahurim, then fled to David', 'Hushai wrote a letter hidden in bread sent across the Jordan', 'Zadok the priest carried the message himself by night', 'Two Levites disguised as merchants carried the message', 'a', 'A woman told Ahimaaz and Jonathan (who hid in a well at Bahurim when spotted), and they went and told king David (2 Samuel 17:17-21).'),
('2 Samuel', 17, 'teens', 5, 'Who sheltered Ahimaaz and Jonathan when Absalom''s servant searched for them?', 'A woman of Bahurim who hid them in a well and covered it with ground corn', 'A Levite who hid them in the tabernacle storeroom', 'A widow in the Jordan valley who disguised them as farmhands', 'The priests of Nob who sheltered them in the sanctuary', 'a', 'There was a well in the court of a man of Bahurim; a woman spread a covering over the well''s mouth and spread ground corn on it, so Absalom''s servants found them not (2 Samuel 17:18-20).'),
-- Adults
('2 Samuel', 17, 'adults', 1, 'What was the strategic genius of Ahithophel''s plan that Hushai acknowledged in order to refute it?', 'It would kill David alone quickly before his forces could regroup, preventing a prolonged civil war and saving lives on both sides', 'It minimized the risk of defections to David from the army', 'It used the terrain of the Jordan valley to David''s disadvantage', 'It would cut off David''s supply lines before he could cross the Jordan', 'a', 'Ahithophel''s plan was to strike while David was weary and weak-handed, kill the king only, and bring all the people back as a bride returns to her husband (2 Samuel 17:2-3). Hushai acknowledged David''s mighty men and the danger of failure (17:8-10) to undercut confidence in the swift plan.'),
('2 Samuel', 17, 'adults', 2, 'What memorable analogy did Hushai use to describe how Israel would fall upon David under his plan?', 'As the dew falleth on the ground, so shall we come upon him in one of the places where he shall be found', 'As a lion pounces on its prey in the night', 'As the flood overtakes the valley', 'As the eagle swoops down from the mountain', 'a', 'Hushai said, "We will light upon him as the dew falleth on the ground: and of him and of all the men that are with him there shall not be left so much as one" (2 Samuel 17:12).'),
('2 Samuel', 17, 'adults', 3, 'Who was Shobi the son of Nahash and what did he bring to David at Mahanaim?', 'He was the son of the king of Ammon who brought beds, basins, earthen vessels, wheat, barley, flour, parched corn, beans, lentils, honey, butter, sheep, and cheese to David', 'He was a Philistine commander who defected to David with weapons', 'He was a Gileadite elder who supplied David with soldiers', 'He was a Levite who brought sacred offerings for David''s troops', 'a', 'Shobi the son of Nahash of Rabbah of Ammon, Machir the son of Ammiel of Lo-debar, and Barzillai brought beds, basins, earthen vessels, wheat, barley, flour, parched corn, beans, lentils, honey, butter, sheep, and cheese of kine for David and his people (2 Samuel 17:27-29).'),
('2 Samuel', 17, 'adults', 4, 'What does the suicide of Ahithophel theologically parallel in the New Testament?', 'It parallels the suicide of Judas Iscariot, who also hanged himself after his counsel led to the betrayal of the Lord''s anointed', 'It parallels Samson''s death in that both involved self-destruction for a greater cause', 'It parallels the death of Ananias and Sapphira for dishonesty before God''s king', 'It parallels the stoning of Stephen in that both were victims of religious political schemes', 'a', 'Ahithophel, David''s trusted friend who betrayed him (paralleling Psalm 41:9, "mine own familiar friend...hath lifted up his heel against me"), hanged himself when his counsel failed (2 Samuel 17:23), mirroring Judas who betrayed Jesus and hanged himself (Matthew 27:5).'),
('2 Samuel', 17, 'adults', 5, 'Where did Ahithophel go to die and what does his making his "house in order" suggest?', 'He went to his house in his own city, put his house in order and was buried in his father''s sepulchre — suggesting a planned, deliberate death', 'He died in the field outside Jerusalem after wandering alone', 'He was found dead in his chamber in Jerusalem', 'He killed himself on the road to Mahanaim', 'a', 'Ahithophel put his household in order, and hanged himself, and died, and was buried in the sepulchre of his father (2 Samuel 17:23), indicating a premeditated, organized act of self-destruction.'),
('2 Samuel', 17, 'adults', 6, 'What was the location where David arrived and was received by supporters?', 'Mahanaim', 'Beersheba', 'Jericho', 'Gilgal', 'a', 'David came to Mahanaim (2 Samuel 17:24), the same city that had been Ish-bosheth''s capital, where supporters including Shobi, Machir, and Barzillai met him with provisions.'),
('2 Samuel', 17, 'adults', 7, 'Who was leading Absalom''s army, and to what earlier commander is he compared in terms of his military role?', 'Amasa the son of Ithra, a role paralleling Joab''s role as David''s commander', 'Shimei the Benjamite who led the tribal militia', 'Ahithophel himself commanded the vanguard before his death', 'Ittai the Gittite who had switched his loyalty to Absalom', 'a', 'Absalom had made Amasa captain of the host instead of Joab: and Amasa was a man''s son, whose name was Ithra an Israelite (2 Samuel 17:25).'),
('2 Samuel', 17, 'adults', 8, 'How does God''s sovereignty over human counsel feature in the narrative comment of 2 Samuel 17:14?', 'The narrator explicitly states that the LORD appointed to defeat Ahithophel''s counsel to bring evil upon Absalom, showing that Absalom''s free choice was simultaneously God''s judicial sentence', 'The passage shows that God rewards the righteous counselor and punishes the wicked one', 'It demonstrates that human wisdom cannot prevail when God withholds his blessing', 'It illustrates that even the wisest men are subject to the fallibility of human reason', 'a', '"For the LORD had appointed to defeat the good counsel of Ahithophel, to the intent that the LORD might bring evil upon Absalom" (2 Samuel 17:14) — the narrator reveals divine sovereignty working through human deliberation, fulfilling David''s prayer in 2 Samuel 15:31.');

-- ═══ 2 Samuel Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 18, 'kids', 1, 'Where did Absalom get caught during the battle?', 'His head caught fast in a great oak tree', 'He fell into a pit in the forest', 'He was surrounded by David''s soldiers', 'His horse fell and trapped him', 'a', 'Absalom rode upon a mule, and the mule went under the thick boughs of a great oak, and his head caught hold of the oak, and he was taken up between the heaven and the earth (2 Samuel 18:9).'),
('2 Samuel', 18, 'kids', 2, 'Who killed Absalom while he hung in the tree?', 'Joab', 'David', 'Abishai', 'Ittai', 'a', 'Joab took three darts in his hand, and thrust them through the heart of Absalom, while he was yet alive in the midst of the oak (2 Samuel 18:14).'),
('2 Samuel', 18, 'kids', 3, 'What did David cry out when he heard that Absalom was dead?', '"O my son Absalom, my son, my son Absalom! would God I had died for thee"', '"The battle is over; let us return to Jerusalem"', '"Thanks be to God who has given us victory"', '"Let Absalom''s death be a warning to all rebels"', 'a', 'The king was much moved, and went up to the chamber over the gate, and wept: and thus he said, "O my son Absalom, my son, my son Absalom! would God I had died for thee, O Absalom, my son, my son!" (2 Samuel 18:33).'),
-- Teens
('2 Samuel', 18, 'teens', 1, 'What specific command did David give his three commanders about Absalom before the battle?', '"Deal gently for my sake with the young man, even with Absalom"', '"Take Absalom alive and bring him to me"', '"Absalom must not escape across the Jordan"', '"Let Absalom be judged by the elders of Israel"', 'a', 'The king charged Joab and Abishai and Ittai, saying, "Deal gently for my sake with the young man, even with Absalom." And all the people heard when the king gave all the captains charge concerning Absalom (2 Samuel 18:5).'),
('2 Samuel', 18, 'teens', 2, 'Why did the soldier who found Absalom in the tree refuse to kill him?', 'He said even for a thousand shekels of silver he would not put forth his hand against the king''s son, for the king had commanded to save Absalom', 'He feared Absalom would be rescued by his supporters', 'He believed it was unlawful to kill a prince', 'He wanted to bring Absalom to Joab first', 'a', 'The man said, "Though I should receive a thousand shekels of silver in mine hand, yet would I not put forth mine hand against the king''s son: for in our hearing the king charged thee and Abishai and Ittai, saying, Beware that none touch the young man Absalom" (2 Samuel 18:12).'),
('2 Samuel', 18, 'teens', 3, 'How was the battle described in terms of where more men died?', 'The wood devoured more people that day than the sword devoured', 'David''s army won a great victory in the open field', 'Absalom''s forces fled to the Jordan and many drowned', 'The battle raged for three days in the hills of Ephraim', 'a', 'The battle was there scattered over the face of all the country: and the wood devoured more people that day than the sword devoured (2 Samuel 18:8).'),
('2 Samuel', 18, 'teens', 4, 'How did Joab respond when the soldier told him he had found Absalom in the tree but refused to kill him?', 'Joab said he would not tarry thus with the soldier, took three darts, and thrust them through Absalom''s heart himself', 'Joab sent ten of his armourbearer to finish the task', 'Joab rebuked the soldier for cowardice', 'Joab went to David first to ask permission', 'a', 'Joab said, "I may not tarry thus with thee," and took three darts in his hand, and thrust them through the heart of Absalom (2 Samuel 18:14).'),
('2 Samuel', 18, 'teens', 5, 'Who ran first to bring David news of the battle, and who ran second?', 'Ahimaaz the son of Zadok ran first, and Cushi ran second', 'Cushi ran first and Ahimaaz ran second', 'Joab''s armor-bearer ran first and Ahimaaz ran second', 'A soldier ran first and Hushai ran second', 'a', 'Ahimaaz asked Joab to let him run first; Joab sent Cushi first, but then allowed Ahimaaz to run also, and Ahimaaz outran Cushi (2 Samuel 18:19-23).'),
-- Adults
('2 Samuel', 18, 'adults', 1, 'How large were the forces when David numbered the people, and how did he divide them?', 'He divided them into three parts: a third under Joab, a third under Abishai the brother of Joab, and a third under Ittai the Gittite', 'He put them all under Joab''s command', 'He divided them into two equal forces guarding both flanks', 'He sent a vanguard of twelve thousand and kept the rest in reserve', 'a', 'David numbered the people...and set captains of thousands and hundreds over them; David sent a third of the people under the hand of Joab, a third under Abishai, and a third under Ittai the Gittite (2 Samuel 18:1-2).'),
('2 Samuel', 18, 'adults', 2, 'What argument did the people use to persuade David not to go into battle himself?', 'They said, "Thou shalt not go forth: for if we flee away, they will not care for us; neither if half of us die, will they care for us: but now thou art worth ten thousand of us"', 'They said David was too old to fight effectively', 'They said David''s presence would draw all of Absalom''s forces onto one place', 'They said the LORD had forbidden David to fight his own son', 'a', 'The people said, "Thou shalt not go forth...for thou art worth ten thousand of us: therefore now it is better that thou succour us out of the city" (2 Samuel 18:3).'),
('2 Samuel', 18, 'adults', 3, 'What did Joab do with Absalom''s body after killing him, and what did the people do?', 'Joab cast him into a great pit in the wood and laid a very great heap of stones upon him; all Israel fled every one to his tent', 'He left the body hanging in the oak as a warning', 'He buried him with honor at the king''s command', 'He sent the body to David for burial', 'a', 'Joab cast Absalom into a great pit in the wood, and laid a very great heap of stones upon him: and all Israel fled every one to his tent (2 Samuel 18:17).'),
('2 Samuel', 18, 'adults', 4, 'What had Absalom set up for himself as a monument, and why?', 'A pillar in the king''s dale, because he had no son to keep his name in remembrance', 'A monument in Hebron to mark his coronation site', 'A carved stone on the Mount of Olives honoring his mother', 'A temple inscription listing his military victories', 'a', 'Absalom in his lifetime had taken and reared up for himself a pillar in the king''s dale: for he said, "I have no son to keep my name in remembrance": and he called the pillar after his own name: and it is called unto this day Absalom''s place (2 Samuel 18:18).'),
('2 Samuel', 18, 'adults', 5, 'What message did Ahimaaz bring David, and why was his message incomplete?', 'He said there was great tumult but said he knew not what when asked about Absalom; he did not tell David Absalom was dead', 'He gave David the full account of Absalom''s death immediately', 'He told David the battle was won but that Joab had been wounded', 'He delivered a sealed letter from Joab without speaking', 'a', 'Ahimaaz called out that the LORD had blessed the king and delivered the enemies, but when the king asked about Absalom, Ahimaaz said, "When Joab sent the king''s servant...I saw a great tumult, but I knew not what it was" (2 Samuel 18:28-29).'),
('2 Samuel', 18, 'adults', 6, 'What was Cushi''s report about Absalom to David?', 'He said the enemies of my lord the king, and all that rise against thee to do thee hurt, be as that young man is', 'He gave a detailed military report of how Joab killed Absalom', 'He said Absalom had escaped across the Jordan before the battle ended', 'He reported only that the battle was won and said nothing of Absalom', 'a', 'Cushi said, "The enemies of my lord the king, and all that rise against thee to do thee hurt, be as that young man is" (2 Samuel 18:32).'),
('2 Samuel', 18, 'adults', 7, 'How does 2 Samuel 18 portray the conflict between Joab''s military pragmatism and David''s paternal grief?', 'Joab kills Absalom in defiance of the king''s explicit command, judging the military necessity above the king''s personal wishes', 'Both Joab and David agree that Absalom must die but disagree on the manner of execution', 'Joab is shown to be righteous in killing Absalom because Absalom was a rebel', 'David''s command to spare Absalom is overruled by the elders of Israel who demand Absalom''s death', 'a', 'David commanded all three captains, "Deal gently...with Absalom" (2 Samuel 18:5), yet Joab killed him with his own hand (18:14), reasoning that Absalom alive would be a perpetual threat — a choice that earned Joab David''s bitter grief and later David''s command to Solomon to deal with Joab (1 Kings 2:5-6).'),
('2 Samuel', 18, 'adults', 8, 'What literary and theological significance does David''s lament "O my son Absalom!" carry in the broader narrative?', 'It shows David''s personal anguish eclipsing his joy as king, and echoes his role as a father who loved a rebel son — a type of God''s grief over wayward children', 'It demonstrates that David had secretly planned to pardon Absalom after the war', 'It shows David''s unfitness to continue as king because he could not subordinate emotion to duty', 'It is primarily a political statement mourning the loss of his heir apparent', 'a', 'David''s sevenfold cry "O my son Absalom!" (2 Samuel 18:33, 19:4) reveals a father''s love that outlasts betrayal. Theologians see in it a picture of God''s longsuffering grief over human rebellion, and the text became a model for penitential literature.');

-- ═══ 2 Samuel Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 19, 'kids', 1, 'Who rebuked David for mourning too much and told him he had shamed his soldiers?', 'Joab', 'Nathan the prophet', 'Zadok the priest', 'Ittai the Gittite', 'a', 'Joab came into the house to the king, and said...thou hast shamed this day the faces of all thy servants...arise, go forth, and speak comfortably unto thy servants (2 Samuel 19:5-7).'),
('2 Samuel', 19, 'kids', 2, 'Who was the man who had cursed David with stones, and what did David say about punishing him when he came to beg forgiveness?', 'Shimei the son of Gera, and David swore that he would not kill him', 'Mephibosheth, and David gave him back his lands', 'Ziba, and David forgave him his debt', 'Amasa, and David made him a commander', 'a', 'Shimei the son of Gera fell down before the king, and the king said, "Thou shalt not die": and the king sware unto him (2 Samuel 19:18, 23).'),
('2 Samuel', 19, 'kids', 3, 'Who was the very old man from Gilead who had helped David and was now offered a reward but chose to go home instead?', 'Barzillai', 'Mephibosheth', 'Jonadab', 'Shobi', 'a', 'Barzillai the Gileadite came down from Rogelim...and the king said unto Barzillai, "Come thou over with me," but Barzillai asked to be allowed to go back to his own city (2 Samuel 19:31-37).'),
-- Teens
('2 Samuel', 19, 'teens', 1, 'What threat did Joab make to David if he did not go out and encourage his troops after Absalom''s death?', 'He said if David did not arise, not a man would remain with him that night, and this would be worse for David than all the evil that had befallen him', 'He said he would take command of the kingdom himself', 'He threatened to leave David''s service with all his soldiers', 'He said the men of Israel would elect a new king by morning', 'a', 'Joab told David, "If thou go not forth, there will not tarry one with thee this night: and that will be worse unto thee than all the evil that befell thee from thy youth until now" (2 Samuel 19:7).'),
('2 Samuel', 19, 'teens', 2, 'What happened concerning Amasa that David arranged before crossing back to Jerusalem?', 'David said to Amasa, "Art thou not of my bone, and of my flesh?" and made him captain of the host instead of Joab', 'David had Amasa arrested for leading Absalom''s army', 'David gave Amasa a pardon but stripped him of all rank', 'David sent Amasa back to lead Judah''s army from Hebron', 'a', 'David said to Amasa, "Art thou not of my bone, and of my flesh? God do so to me, and more also, if thou be not captain of the host before me continually in the room of Joab" (2 Samuel 19:13).'),
('2 Samuel', 19, 'teens', 3, 'What argument broke out between Israel and Judah as they brought David back?', 'Israel accused Judah of stealing the king, and Judah said the king was near of kin to them; Israel replied they had ten parts in the king and were first to bring him back', 'The two sides argued about who should get the larger share of David''s gifts', 'Israel accused Judah of refusing to fight against Absalom', 'Judah accused Israel of secretly supporting Absalom', 'a', 'The men of Israel said to Judah, "We have ten parts in the king...why then did ye despise us?" And the men of Judah answered the men of Israel (2 Samuel 19:43).'),
('2 Samuel', 19, 'teens', 4, 'What did Mephibosheth tell David about why he had not accompanied him in flight?', 'He said his servant Ziba had deceived him; Mephibosheth had saddled an ass to go with David but Ziba had slandered him', 'He said he was too ill to travel on foot', 'He said the priests had told him to remain in Jerusalem as a witness', 'He said he feared being captured by Absalom on the road', 'a', 'Mephibosheth said, "My lord, O king, my servant did deceive me: for thy servant said, I will saddle me an ass, that I may ride thereon, and go to the king; because thy servant is lame. And he hath slandered thy servant unto my lord the king" (2 Samuel 19:26-27).'),
('2 Samuel', 19, 'teens', 5, 'How old was Barzillai and what reasons did he give for not going to Jerusalem with David?', 'He was fourscore years old and said he could not discern good and evil, nor taste what he ate or drank, nor hear the voice of singing men and women', 'He was seventy years old and said his family needed him in Gilead', 'He was sixty years old and said his health was too poor to make the journey', 'He was ninety years old and said God had forbidden him to leave his ancestral land', 'a', 'Barzillai said to the king, "I am this day fourscore years old: and can I discern between good and evil? can thy servant taste what I eat or what I drink? can I hear any more the voice of singing men and singing women?" (2 Samuel 19:35).'),
-- Adults
('2 Samuel', 19, 'adults', 1, 'What position did David take while mourning, according to the report that reached Joab''s soldiers?', 'The king covered his face and cried with a loud voice, "O my son Absalom, O Absalom, my son, my son!"', 'David shut himself in the chamber over the gate and refused all food for three days', 'David sat in the throne room weeping and tearing his robe', 'David went out alone to the Jordan riverbank', 'a', 'The king covered his face, and the king cried with a loud voice, "O my son Absalom, O Absalom, my son, my son!" (2 Samuel 19:4).'),
('2 Samuel', 19, 'adults', 2, 'What political problem did David face in re-establishing his rule over Judah, and how did he solve it?', 'Judah had not invited David back; he sent to Zadok and Abiathar to ask the elders of Judah why they were last to bring him home, and sweetened it by promising to make Amasa his captain', 'Israel was blocking David''s crossing of the Jordan', 'The priests refused to restore David because of his sin with Bathsheba', 'Joab threatened to support a rival claimant unless David returned quickly', 'a', 'David sent to Zadok and Abiathar, "Speak unto the elders of Judah, saying, Why are ye the last to bring the king back to his house? ye are my brethren, ye are my bones and my flesh: wherefore then are ye the last?" And he promised Amasa the captaincy (2 Samuel 19:11-13).'),
('2 Samuel', 19, 'adults', 3, 'What was the theological issue Abishai raised when he objected to pardoning Shimei?', 'He said Shimei should die because he cursed the LORD''s anointed', 'He said pardoning Shimei would signal weakness to Israel''s enemies', 'He appealed to the Mosaic law against cursing the king', 'He said it would dishonor the memory of Absalom to pardon his supporter', 'a', 'Abishai said, "Shall not Shimei be put to death for this, because he cursed the LORD''s anointed?" (2 Samuel 19:21).'),
('2 Samuel', 19, 'adults', 4, 'What reason did David give for pardoning Shimei on the day of his return?', 'He said shall any man be put to death in Israel this day, knowing that today I am king over Israel', 'He said he was bound by his oath and could not go back on his word', 'He said God had commanded him in a dream to show mercy', 'He said Shimei was old and near death and would soon answer to God', 'a', 'David said, "Shall there any man be put to death this day in Israel? for do not I know that I am this day king over Israel?" (2 Samuel 19:22).'),
('2 Samuel', 19, 'adults', 5, 'What did David say to Mephibosheth about the land dispute with Ziba, and what does Mephibosheth''s answer reveal?', 'David said they should divide the land; Mephibosheth said Ziba could take it all since the king had returned in peace — revealing Mephibosheth''s true loyalty', 'David restored all the land to Mephibosheth and punished Ziba', 'David told Mephibosheth the matter was closed and he would not revisit it', 'David gave all the land to Ziba as he had already sworn', 'a', 'David said, "Why speakest thou any more of thy matters? I have said, Thou and Ziba divide the land." Mephibosheth said, "Yea, let him take all, forasmuch as my lord the king is come again in peace" (2 Samuel 19:29-30).'),
('2 Samuel', 19, 'adults', 6, 'What symbolic gesture of loyalty did Chimham (Barzillai''s son) represent in the narrative?', 'Barzillai sent Chimham in his own place to go with David to Jerusalem, so David could bless him there, showing generational transfer of loyalty from old ally to young heir', 'Chimham carried David''s royal regalia back to Jerusalem', 'Chimham was Barzillai''s slave whom he freed as a gift to David', 'Chimham was appointed governor of the region east of Jordan as a reward', 'a', 'Barzillai said, "Behold thy servant Chimham; let him go over with my lord the king; and do to him what shall seem good unto thee" (2 Samuel 19:37-38).'),
('2 Samuel', 19, 'adults', 7, 'What does Joab''s rebuke of David in chapter 19 reveal about the tension between kingly grief and royal duty?', 'Joab argues that David''s public mourning was shaming the soldiers who had saved his life and threatening the stability of the kingdom', 'Joab argues that David was grieving too long for a traitor', 'Joab challenges David''s right to mourn a son who had tried to kill him', 'Joab''s rebuke was primarily a political power move to restore his own influence', 'a', 'Joab told David that he had shamed those who had saved his life and the lives of his household, and that David seemed to love those who hated him and hate those who loved him, warning that no one would be left if David did not act (2 Samuel 19:5-7).'),
('2 Samuel', 19, 'adults', 8, 'How does the quarrel between Israel and Judah at the end of chapter 19 foreshadow the permanent division of the kingdom?', 'The tribal jealousy over who had more right to the king — Israel''s "ten parts" versus Judah''s blood kinship — reveals the fault line that Sheba exploits in chapter 20 and that splits the kingdom under Rehoboam in 1 Kings 12', 'It shows that the northern tribes had accepted Absalom''s rebellion and were being punished', 'It is merely a protocol dispute over ceremony with no deeper significance', 'It shows that Joab''s army from Judah had been favored while Israel''s men were excluded', 'a', 'The men of Israel complained that Judah had stolen the king (2 Samuel 19:41-43), and the words of Israel were fiercer than the words of Judah. This rivalry directly triggers Sheba''s revolt (20:1-2) and previews the Israel-Judah split (1 Kings 12:16).');

-- ═══ 2 Samuel Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 20, 'kids', 1, 'What did Sheba the son of Bichri say when he blew a trumpet and started a new rebellion?', '"We have no part in David, neither have we inheritance in the son of Jesse"', '"Let Absalom be our king"', '"Let us return to our tents, O Israel"', '"David has forsaken the LORD''s covenant"', 'a', 'Sheba blew a trumpet, and said, "We have no part in David, neither have we inheritance in the son of Jesse: every man to his tents, O Israel" (2 Samuel 20:1).'),
('2 Samuel', 20, 'kids', 2, 'How did the wise woman of Abel save her city?', 'She persuaded the people to cut off Sheba''s head and throw it over the wall to Joab', 'She opened the gates and negotiated a peace treaty', 'She hid Sheba in the city until Joab left', 'She sent a message to David asking for mercy', 'a', 'The woman went unto all the people in her wisdom: and they cut off the head of Sheba the son of Bichri, and cast it out to Joab (2 Samuel 20:22).'),
('2 Samuel', 20, 'kids', 3, 'Who did Joab kill treacherously at the start of chapter 20?', 'Amasa', 'Shimei', 'Ittai', 'Benaiah', 'a', 'Joab took Amasa by the beard with the right hand to kiss him, and smote him with a sword in the fifth rib, and he died (2 Samuel 20:9-10).'),
-- Teens
('2 Samuel', 20, 'teens', 1, 'What task had David given Amasa that he failed to complete on time?', 'David told Amasa to assemble the men of Judah within three days to pursue Sheba, but Amasa tarried beyond the set time', 'David sent Amasa to negotiate a peace with Sheba', 'David ordered Amasa to fortify the northern border cities', 'David told Amasa to take a census of all able-bodied men', 'a', 'David said to Amasa, "Assemble me the men of Judah within three days, and be thou here present." So Amasa went to assemble the men of Judah: but he tarried longer than the set time (2 Samuel 20:4-5).'),
('2 Samuel', 20, 'teens', 2, 'Why was the pursuit of Sheba considered urgent by David?', 'He said Sheba would do more harm than Absalom, and must not get himself into fenced cities and escape', 'He said Sheba had allied with the Philistines', 'He said God had told him Sheba would overthrow the kingdom', 'He said Sheba had stolen the ark of the covenant', 'a', 'David said to Abishai, "Now shall Sheba...do us more harm than did Absalom: take thou thy lord''s servants, and pursue after him, lest he get him fenced cities, and escape us" (2 Samuel 20:6).'),
('2 Samuel', 20, 'teens', 3, 'What did the wise woman of Abel call her city as she persuaded Joab not to destroy it?', 'She called it a mother in Israel and a city peaceable and faithful, and asked why he would swallow up the inheritance of the LORD', 'She called it a city of priests dedicated to God', 'She called it the oldest city in the tribe of Dan', 'She called it a city of refuge protected by the law of Moses', 'a', 'The woman said, "I am one of them that are peaceable and faithful in Israel: thou seekest to destroy a city and a mother in Israel: why wilt thou swallow up the inheritance of the LORD?" (2 Samuel 20:19).'),
('2 Samuel', 20, 'teens', 4, 'What had Joab''s men done to Amasa''s body in the road after killing him?', 'He wallowed in blood in the midst of the highway, and a man covered him with a cloth when he saw the people stopped', 'They buried him honorably at the side of the road', 'They left him there publicly as a warning to other rebels', 'They carried his body back to Jerusalem', 'a', 'Amasa wallowed in blood in the midst of the highway...when the man saw that all the people stood still, he removed Amasa out of the highway into the field, and cast a cloth upon him (2 Samuel 20:12).'),
('2 Samuel', 20, 'teens', 5, 'What was the list of David''s chief officers given at the end of chapter 20?', 'Joab over the host, Benaiah over the Cherethites and Pelethites, Adoram over the tribute, Jehoshaphat the recorder, Sheva the scribe, Zadok and Abiathar the priests, and Ira the chief ruler', 'Amasa over the host, Hushai over counsel, Nathan the prophet, and Abiathar the priest', 'Abishai over the host, Joab over the treasury, and Zadok the high priest', 'Ittai over the host, Joab over the body guard, and Nathan the recorder', 'a', 'So Joab was over all the host of Israel: and Benaiah the son of Jehoiada was over the Cherethites and over the Pelethites: And Adoram was over the tribute: and Jehoshaphat the son of Ahilud was recorder: And Sheva was scribe: and Zadok and Abiathar were the priests: And also Ira the Jairite was a chief ruler about David (2 Samuel 20:23-26).'),
-- Adults
('2 Samuel', 20, 'adults', 1, 'What was the ethnic identity of Sheba and why was it significant to the tribal politics of the day?', 'Sheba was a Benjamite, the tribe of Saul, and his revolt tapped into the same tribal resentment that had supported Ish-bosheth''s rival kingdom', 'Sheba was from the tribe of Ephraim and led the northern rebellion', 'Sheba was from the tribe of Gad and had supported Absalom before this', 'Sheba was a Canaanite mercenary who exploited the civil war for personal gain', 'a', 'Sheba the son of Bichri, a Benjamite (2 Samuel 20:1) — the tribe of Saul — exploited the quarrel between Israel and Judah (19:41-43), and all the men of Israel followed him (20:2), showing that Saul''s tribal loyalties had never fully transferred to David.'),
('2 Samuel', 20, 'adults', 2, 'What was the situation of the ten concubines David had left to keep the house, after his return?', 'David fed them but went not in unto them, and they were shut up unto the day of their death, living in widowhood', 'David restored them to full status as concubines in his household', 'David sent them to their families with a provision of silver', 'David gave them to his sons as wives to cement political alliances', 'a', 'David came to his house at Jerusalem; and the king took the ten women his concubines...and put them in ward, and fed them, but went not in unto them. So they were shut up unto the day of their death, living in widowhood (2 Samuel 20:3).'),
('2 Samuel', 20, 'adults', 3, 'How did Joab use the pretense of greeting Amasa with a kiss to kill him?', 'He took Amasa by the beard with his right hand as if to kiss him, while his sword fell out in his left hand and he smote Amasa in the fifth rib without a second blow', 'He distracted Amasa with conversation and then stabbed him from behind', 'He arranged an ambush at a city gate disguised as a military parade', 'He poisoned the wine cup he shared with Amasa before the meeting', 'a', 'Joab said, "Art thou in health, my brother?" and took Amasa by the beard with the right hand to kiss him. But Amasa took no heed to the sword that was in Joab''s hand: and he smote him therewith in the fifth rib (2 Samuel 20:9-10).'),
('2 Samuel', 20, 'adults', 4, 'What does the negotiation between Joab and the wise woman of Abel illustrate about ancient Israelite city law?', 'It shows that an accused city could first seek terms of peace before being attacked, reflecting the principle of Deuteronomy 20:10-12, and that cities had wise leaders empowered to surrender wanted men', 'It shows that women held formal judicial authority in Israelite cities', 'It illustrates the custom of ransom negotiations before a siege began', 'It demonstrates that Joab was bound by law to accept surrender of individuals before destroying a city', 'a', 'The wise woman negotiated on behalf of the city (2 Samuel 20:16-22), reflecting the law that requires an offer of peace before attacking an Israelite city (Deuteronomy 20:10-12); she identified Sheba as the guilty party and secured the city''s safety by delivering his head.'),
('2 Samuel', 20, 'adults', 5, 'What ancient proverb did the wise woman invoke in her negotiation with Joab?', 'She said, "They were wont to speak in old time, saying, They shall surely ask counsel at Abel: and so they ended the matter"', 'She said, "A city that opens its gates to peace shall not be destroyed"', 'She quoted, "The blood of the innocent cries out from the ground"', 'She said, "Where the king''s word is, there is power"', 'a', 'The woman said, "They were wont to speak in old time, saying, They shall surely ask counsel at Abel: and so they ended the matter" (2 Samuel 20:18).'),
('2 Samuel', 20, 'adults', 6, 'What does Joab''s killing of Amasa in chapter 20 reveal about Joab''s character and his grip on power?', 'It reveals that Joab was unwilling to be displaced from his position as commander, eliminating any rival David appointed — having already killed Abner and Absalom', 'It shows Joab was acting on secret orders from David who resented Amasa', 'It demonstrates that Amasa was genuinely a traitor who deserved to die', 'It reveals that Joab feared Amasa would expose his killing of Absalom against David''s orders', 'a', 'Joab had already killed Abner (2 Samuel 3:27) when David made Abner his commander, and now kills Amasa (20:10) when David appointed Amasa over Joab; in both cases Joab used treacherous deceit to eliminate rivals, and David acknowledged this pattern on his deathbed (1 Kings 2:5).'),
('2 Samuel', 20, 'adults', 7, 'What is the significance of the detail that the soldier who stood by Amasa''s body said, "He that favoureth Joab, and he that is for David, let him go after Joab"?', 'It shows the soldiers equated loyalty to Joab with loyalty to David, reflecting Joab''s power over the army despite his crimes', 'It reveals that the soldiers were confused about who was in command after Amasa''s death', 'It demonstrates that the men of Judah had transferred their loyalty from David to Joab', 'It shows that Joab had publicly announced his claim to lead the army', 'a', 'A man of Joab''s men stood by Amasa and said, "He that favoureth Joab, and he that is for David, let him go after Joab" (2 Samuel 20:11), showing that Joab had made himself synonymous with David''s cause to maintain control.'),
('2 Samuel', 20, 'adults', 8, 'How does 2 Samuel 20 bring the Absalom rebellion narrative to a full structural close?', 'The chapter resolves the political crisis (Sheba suppressed), restores the administrative list (David''s officers reestablished), and returns Joab to power — completing the frame opened by Absalom''s revolt in chapter 15', 'The chapter ends with David repenting publicly for all sins committed during the rebellion', 'The chapter closes with a covenant renewal ceremony at the tabernacle', 'The chapter ends with the oracle of Nathan confirming David''s restored standing before God', 'a', 'Chapter 20 ends the long rebellion narrative (chapters 13-20) with Sheba killed (20:22), David''s officers listed (20:23-26), and Joab back in command — forming a literary and political closure that mirrors the stable reign described before the rebellion began in chapter 11.');
